/**
 * @param {number[][]} grid
 * @return {number}
 */
function solve(grid) {
    const m = grid.length;
    const n = grid[0].length;

    // The problem constraint m * n <= 1000 suggests that a DP approach
    // or a variation of search might be feasible.
    // Since we are looking for the minimum XOR sum, and the path length is fixed (m + n - 1),
    // this smells like a dynamic programming problem, but standard DP for min/max
    // usually works with addition/multiplication, not XOR.

    // Given the XOR nature, and the small constraint (m*n <= 1000),
    // the maximum possible XOR value is less than 2^10 (since grid[i][j] <= 1023 < 2^10).
    // This suggests we might be able to use a meet-in-the-middle approach or DP on the XOR value.

    // The total path length is L = m + n - 1.
    // The "middle" step is roughly when we have taken k = floor((m + n - 1) / 2) steps.
    // Any cell (r, c) such that r + c = k is on a potential middle layer.

    // Meet-in-the-Middle Approach:
    // 1. Traverse from (0, 0) to all cells (r, c) such that r + c = k. Store all possible XOR sums to reach these cells.
    // 2. Traverse backwards from (m-1, n-1) to all cells (r, c) such that r + c = k. Store all possible XOR sums from these cells to the end.
    // 3. For each cell (r, c) at the middle layer, find the minimum XOR of (XOR_forward XOR XOR_backward_reversed) over all stored values.

    // Let k = floor((m + n - 2) / 2). We want to reach cells (r, c) such that r + c = k.
    // The path length to (r, c) is r + c.
    const target_sum = Math.floor((m + n - 2) / 2);

    // Map to store all possible XOR sums to reach a cell (r, c) where r + c = target_sum.
    // Key format: "r,c" -> Set of XOR sums
    const forward_paths = new Map();

    // Step 1: Forward traversal
    // Queue stores [r, c, current_xor]
    const queue = [[0, 0, grid[0][0]]];
    const visited_forward = new Set(["0,0"]);

    while (queue.length > 0) {
        const [r, c, xor_sum] = queue.shift();

        if (r + c === target_sum) {
            const key = `${r},${c}`;
            if (!forward_paths.has(key)) {
                forward_paths.set(key, new Set());
            }
            forward_paths.get(key).add(xor_sum);
        }

        // Optimization: If we have gone past the middle layer, stop exploring this branch for the forward pass.
        if (r + c > target_sum) continue;

        // Move Down
        if (r + 1 < m && !(r + 1) + c > target_sum) {
            const nr = r + 1;
            const nc = c;
            if (!visited_forward.has(`${nr},${nc}`)) {
                const next_xor = xor_sum ^ grid[nr][nc];
                queue.push([nr, nc, next_xor]);
                visited_forward.add(`${nr},${nc}`);
            }
        }

        // Move Right
        if (c + 1 < n && r + (c + 1) <= target_sum) {
            const nr = r;
            const nc = c + 1;
            if (!visited_forward.has(`${nr},${nc}`)) {
                const next_xor = xor_sum ^ grid[nr][nc];
                queue.push([nr, nc, next_xor]);
                visited_forward.add(`${nr},${nc}`);
            }
