    // This is complicated because grid[r][c] is included in both.

    // A simpler way for MITM with XOR:
    // X_total = (XOR of path segment 1) XOR (XOR of path segment 2) XOR grid[r][c]
    // Path 1: (0,0) -> (r,c). XOR = F.
    // Path 2: (r,c) -> (m-1, n-1). XOR = S.
    // X_total = F XOR S_excluding_grid_rc.
    // If we define F as XOR up to and including grid[r][c], and S as XOR from grid[r][c] to end,
    // then X_total = F XOR S XOR grid[r][c]. (Since grid[r][c] is XORed twice).
    // Let's define S as the XOR sum of the path segment starting *after* (r, c) up to (m-1, n-1).

    // Let's redefine:
    // F(r, c) = XOR sum from (0, 0) to (r, c) (inclusive).
    // S(r, c) = XOR sum from (r, c) to (m-1, n-1) (inclusive).
    // Total XOR = F(r, c) XOR S(r, c) XOR grid[r][c].

    // We already calculated F(r, c) for all cells where r+c = target_sum in forward_paths.
    // Now calculate S(r, c) for all cells where r+c = target_sum using a backward BFS/DP.

    // Map to store all possible XOR sums S(r, c)
    // Key format: "r,c" -> Set of XOR sums
    const backward_paths = new Map();

    // Queue stores [r, c, current_xor_sum]
    // Start from (m-1, n-1)
    const queue_b = [[m - 1, n - 1, grid[m - 1][n - 1]]];
    const visited_backward = new Set([`${m - 1},${n - 1}`]);

    // The required sum for backward traversal is m + n - 2 - target_sum, which should equal target_sum if m+n-1 is even, or target_sum+1 if m+n-1 is odd.
    // The required sum for cells (r, c) is r + c = target_sum.
    // The path length from (r, c) to (m-1, n-1) is (m-1-r) + (n-1-c).
    // The sum of coordinates for the end point is m-1 + n-1.
