    // If we fix r+c = target_sum, the path length to end is (m-1-r) + (n-1-c).
    // Sum of coordinates: r+c + (m-1-r) + (n-1-c) = m+n-2.
    // The sum of coordinates for the midpoint layer should be target_sum.
    // This means we stop the backward traversal when r+c = target_sum.

    while (queue_b.length > 0) {
        const [r, c, xor_sum] = queue_b.shift();

        if (r + c === target_sum) {
            const key = `${r},${c}`;
            if (!backward_paths.has(key)) {
                backward_paths.set(key, new Set());
            }
            backward_paths.get(key).add(xor_sum);
        }

