        // Move Up (Previous step was Down)
        if (r - 1 >= 0) {
            const nr = r - 1;
            const nc = c;
            if (!visited_backward.has(`${nr},${nc}`)) {
                const next_xor = xor_sum ^ grid[nr][nc];
                queue_b.push([nr, nc, next_xor]);
                visited_backward.add(`${nr},${nc}`);
            }
        }

        // Move Left (Previous step was Right)
        if (c - 1 >= 0) {
            const nr = r;
            const nc = c - 1;
            if (!visited_backward.has(`${nr},${nc}`)) {
                const next_xor = xor_sum ^ grid[nr][nc];
                queue_b.push([nr, nc, next_xor]);
                visited_backward.add(`${nr},${nc}`);
            }
        }
    }

    // Step 3: Combine results
    let min_xor = 2**10; // Max possible XOR value is < 1024

    // Iterate over all common meeting points
    for (const [key, forward_set] of forward_paths.entries()) {
        if (backward_paths.has(key)) {
            const backward_set = backward_paths.get(key);

            for (const f_xor of forward_set) {
                for (const s_xor of backward_set) {
                    // Total XOR = F(r,c) XOR S(r,c) XOR grid[r][c]
                    // F includes grid[r][c], S includes grid[r][c].
                    // f_xor ^ s_xor ^ grid[r][c] = (F ^ grid[r][c]) ^ (S ^ grid[r][c]) ^ grid[r][c]
                    // Let F' = F ^ grid[r][c] (XOR up to but excluding grid[r][c])
                    // Let S' = S ^ grid[r][c] (XOR from but excluding grid[r][c])
                    // Total = F' ^ grid[r][c] ^ S' = (F ^ grid[r][c]) ^ (S ^ grid[r][c])

                    // Simpler formula:
                    const total_xor = f_xor ^ s_xor ^ grid[key.split(',')[0]][key.split(',')[1]];
                    if (total_xor < min_xor) {
                        min_xor = total_xor;
                    }
                }
            }
        }
    }

    return min_xor;
